mapper.select:
select id, code, name, status, version from sys_dict_type
and (code like concat('%', #{keyword}, '%') or name like concat('%', #{keyword}, '%'))
order by id desc limit #{pageSize} offset #{offset}

select count(1) from sys_dict_type
where code = #{code}
and id != #{excludeId}

select id, type_id, label, value, sort, status, version from sys_dict_item

  and type_id = #{typeId}

order by sort asc, id asc
limit #{pageSize} offset #{offset}

mapper.update:
update sys_dict_item
set type_id = #{typeId}, label = #{label}, value = #{value}, sort = #{sort}, status = #{status}, version = version + 1
where id = #{id}

mapper.select:
select count(1) from sys_dict_item
where type_id = #{typeId} and value = #{value}
and id != #{excludeId}
